import { NextResponse } from 'next/server'
import * as cheerio from 'cheerio'
import axios from 'axios'

export async function POST(req: Request) {
    try {
        const { url } = await req.json()

        if (!url) {
            return NextResponse.json({ error: 'URL is required' }, { status: 400 })
        }

        // A simple GET request (may require User-Agent to evade simple bot checks)
        const response = await axios.get(url, {
            headers: {
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/115.0.0.0 Safari/537.36',
                'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,image/avif,image/webp,*/*;q=0.8',
            }
        })

        const html = response.data
        const $ = cheerio.load(html)

        // TikTok products usually have og tags
        let title = $('meta[property="og:title"]').attr('content') || $('title').text()
        let image = $('meta[property="og:image"]').attr('content')

        if (!title && !image) {
            return NextResponse.json({ error: 'Could not extract data from the provide link' }, { status: 404 })
        }

        return NextResponse.json({ title, image, url })
    } catch (err) {
        console.error('Failed to scrape:', err)
        return NextResponse.json({ error: 'Failed to fetch metadata' }, { status: 500 })
    }
}
